func minOperations(word1 string, word2 string) int {
	n := len(word1)
	f := make([]int, n+1)
	for i := range f {
		f[i] = math.MaxInt32
	}
	f[0] = 0

	calc := func(l, r int, rev bool) int {
		var cnt [26][26]int
		res := 0

		for i := l; i <= r; i++ {
			j := i
			if rev {
				j = r - (i - l)
			}
			a := word1[j] - 'a'
			b := word2[i] - 'a'

			if a != b {
				if cnt[b][a] > 0 {
					cnt[b][a]--
				} else {
					cnt[a][b]++
					res++
				}
			}
		}

		return res
	}

	for i := 1; i <= n; i++ {
		for j := 0; j < i; j++ {
			a := calc(j, i-1, false)
			b := 1 + calc(j, i-1, true)
			t := min(a, b)
			f[i] = min(f[i], f[j]+t)
		}
	}

	return f[n]
}

